scwin.load = true;
scwin.vCoCd = $c.gus.cfIsNull($c.data.getMemInfo("coCd")) ? '' : $c.data.getMemInfo("coCd");   // 소속 자회사
scwin.vCoClsCd = $c.gus.cfIsNull($c.data.getMemInfo("coClsCd")) ? '' : $c.data.getMemInfo("coClsCd");   // //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = $c.gus.cfIsNull($c.data.getMemInfo("userHomeClsCd")) ? '' : $c.data.getMemInfo("userHomeClsCd");   // 사용자소속구분코드  
scwin.vAcctDeptCd = $c.gus.cfIsNull($c.data.getMemInfo("acctDeptCd")) ? '' : $c.data.getMemInfo("acctDeptCd");   // 부서
scwin.vAcctDeptNm = $c.gus.cfIsNull($c.data.getMemInfo("acctDeptNm")) ? '' : $c.data.getMemInfo("acctDeptNm");   // 부서명
scwin.vPrivAdmin = $c.gus.cfIsNull($c.data.getMemInfo("privAdmin")) ? '' : $c.data.getMemInfo("privAdmin");
scwin.txtCoClsCd = "";

scwin.isSubCompany = false;

scwin.onpageload = function () {

    const codeOptions = [
        { grpCd: "OP160", compID: "lc_occptypeCd, gr_out:occptypeCd" },
        { grpCd: "OP161", compID: "gr_out:dtlOccptypeCd" },   //상세직종
        { grpCd: "OP268", compID: "gr_out:occpgrdCd" },       //직급
        { grpCd: "FI115", compID: "lc_payGbn, lc_payGbn_param, gr_out:payGbn" },
    ];
    // console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);

    scwin.f_CreateHeader();

};

scwin.onUdcCompleted = function () {
    scwin.f_setDefaultCondition();

    $c.gus.cfEnableBtnOnly([btn_Create]);
    $c.gus.cfDisableBtnOnly([btn_Modify, btn_Save, btn_Cancel, pu_image]);
    scwin.f_DisableData();

    // 동원로엑스 - HR팀, 재경팀은 모든 귀속부서 조회가능
    // 넥스트로 - 기획관리팀(넥스트로) 모든 귀속부서 조회가능
    if (scwin.vAcctDeptCd == "00006" || scwin.vAcctDeptCd == "00009" || scwin.vAcctDeptCd == "01387") {
        $c.gus.cfEnableObjects([ed_acctDeptCd_param, ed_acctDeptNm_param, img_PopUp2]);
        ed_acctDeptCd_param.focus();
    } else {
        $c.gus.cfDisableObjects([ed_acctDeptCd_param, ed_acctDeptNm_param, img_PopUp2]);
    }

    scwin.f_setCompanyInfo();
}

//기본조회 조건 선언 
scwin.f_setDefaultCondition = function () {
    ed_staffNo_param.setValue("");
    ed_staffNm_param.setValue("");
    ed_acctDeptCd_param.setValue("");
    ed_acctDeptNm_param.setValue("");
    lc_payGbn_param.setValue("");
    lc_applyYn_param.setValue("");
    chk_lowerDeptIncluYn.setValue(0);
    ed_acctDeptCd_param.setValue(scwin.vAcctDeptCd);
    ed_acctDeptNm_param.setValue(scwin.vAcctDeptNm);
    ed_acctDeptCd_param.options.hidVal = scwin.vAcctDeptCd;
    ed_acctDeptNm_param.options.hidVal = scwin.vAcctDeptNm;
};

//상세출력내용 전체 활성화 
scwin.f_EnableData = function () {
    // 상세출력창 입력객체 활성화 함수
    $c.gus.cfEnableKeyData();
    // 사원번호는 자동 부여 방식이므로 항상 수정 불가
    ed_staffNo.setDisabled(true);
    // 상세출력창쪽 팝업 객체 활성화 함수
    $c.gus.cfEnableObjects([img_mgntClntNo, img_PopUp3, img_PopUp4, img_PopUp11, img_PopUp12]);
};

//상세출력내용 전체 비활성화 
scwin.f_DisableData = function () {
    // 상세출력창 입력객체 비 활성화 함수
    $c.gus.cfDisableKeyData();
    // 상세출력창쪽 팝업 객체 비활성화 함수
    $c.gus.cfDisableObjects([img_mgntClntNo, img_PopUp3, img_PopUp4, img_PopUp11, img_PopUp12]);
    //$c.gus.cfDisableObjects([img_PopUp3,img_PopUp4, img_PopUp11,img_PopUp12, calendar1,calendar2 ]);
    //$c.gus.cfDisableObjects([img_PopUp3,img_PopUp4, img_PopUp11,img_PopUp12]);
};

