// 조회 버튼 클릭함수 
scwin.f_Retrieve = async function () {

    $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, pu_image]);
    // 조회 버튼 클릭시 하단 상세 정보 출력창은 정부 비활성화
    scwin.f_DisableData();

    if (chk_lowerDeptIncluYn.getValue() == "1") {
        ds_cond.set("lowerDeptIncluYn", 1);
    } else {
        ds_cond.set("lowerDeptIncluYn", 0);
    }

    var res = await $c.gus.cfValidate([ed_coCd]);
    if (!res) {
        return;
    }


    //ds_cond.UseChangeInfo = false;

    //tr_retrieve.Post();
    /*
    ds_cond.set("coCd", "029");
    ds_cond.set("acctDeptCd", "01392");
    ds_cond.set("payGbn", "");
    ds_cond.set("staffNo", "");
    ds_cond.set("applyYn", "");
    */

    $c.sbm.execute(sbm_retrieve);
};

// 신규
scwin.f_Create = function () {

    // 신규열 추가
    let row;
    row = ds_out.insertRow();
    ds_out.setRowPosition(row);
    gr_out.setFocusedCell(row, 0, false);

    // 신규버튼 클리시 수정/신규 버튼은 비활성화 되고, 저장, 취소 버튼은 활성화 된다. 
    $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, pu_image]);
    $c.gus.cfDisableBtnOnly([btn_Create, btn_Modify]);

    // 수정 버튼 클릭시 하단 상세 정보 출력창 전부 활성화
    scwin.f_EnableData();

    // 신규데이터 기본 값 세팅 
    txtCoCd.setValue(ed_coCd.getValue());
    lc_applyYn.setValue("1");	//적용여부-적용
    lc_payGbn.setValue("03");	//급여구분-시급
    lc_occptypeCd.setValue("03");//직종-일용직
    ed_dtlOccptypeCd.setValue("10");//상세직종-일용직
    scwin.f_openCommonPopUp(22, ed_dtlOccptypeCd.getValue(), ed_dtlOccptypeNm.getValue(), 'T', 'F');

    //  lc_workTimeClsCd.BindColVal ="03";//기본작업시간구분
    // 	ed_retireDt.text = "99991231";//일용직

    // 인사팀과 재경팀 이외에는 적용여부 비활성화
    // <%--     if("<%=loginDTO.getAcctDeptCd()%>" == "00006") { --%>
    //     	cfEnableObjects([lc_applyYn]);
    //     } else {   
    //         cfDisableBtnOnly([lc_applyYn]);
    //     }
};

// 저장
scwin.f_Save = async function () {

    // 저장시 변경 데이터가 없을경우 메세지 출력이후 리턴
    if (ds_out.getRowCount() == 0) return;

    if (ds_out.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    // 필수입력사항 확인
    if (!await $c.gus.cfValidate([gr_out])) {
        return;
    }

    // 저장전 급여구분에 따른 필수 입력 체크 
    if (scwin.f_checkRequire() == false) {
        return;
    }

    let vConfirm = await $c.win.confirm("저장하시겠습니까");

    if (vConfirm) {
        // 저장 버튼 클릭시 하단 상세 정보 출력창은 정부 비활성화
        scwin.f_DisableData();

        // 저장 트렌젝션 호출 
        $c.sbm.execute(sbm_save);
    }
};

// 저장전 입력 필수 체크 
scwin.f_checkRequire = function () {
    let i = 0;
    let check_Result = "true";

    let error_String = "";
    for (i = 0; i <= ds_out.getRowCount(); i++) {
        // 필수입력값이 정상적으로 입력되어 있는지 확인 
        if (ds_out.getRowStatusValue(i) == 1 || ds_out.getRowStatusValue(i) == 2) {//수정 또는 신규 상태일경우
            // 근무시작1차
            if (ds_out.getCellData(i, "entDt") == "") {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무시작1차는 필수항목입니다. \n";
                check_Result = false;
            }
            // 				if ( ds_out.NameValue(i,"retireDt") == "") {
            // 					error_String = error_String + 
            // 						( ds_out.NameValue(i,"staffNm") == "" ? "신규입력" : ds_out.NameValue(i,"staffNm") ) + "[" + 
            // 						( ds_out.NameValue(i,"staffNo") == "" ? "신규입력" : ds_out.NameValue(i,"staffNo") ) + "]의  근무종료예정1차는 필수항목입니다. \n";
            // 					check_Result = false;
            // 				}
            // 근무종료예정자 1차.
            if (ds_out.getCellData(i, "retireDt") != "") {
                if (parseInt(ds_out.getCellData(i, "entDt")) >= parseInt(ds_out.getCellData(i, "retireDt"))) {
                    error_String = error_String +
                        (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                        (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무종료예정1차는 근무시작1차와 같거나 이전일수 없습니다. \n";
                    check_Result = false;
                }
            }

            // 근무시작 2차
            // 				if ( ds_out.NameValue(i,"entDtSecond") != "" && ds_out.NameValue(i,"retireDtSecond") == "" ) {
            // 					error_String = error_String + 
            // 						( ds_out.NameValue(i,"staffNm") == "" ? "신규입력" : ds_out.NameValue(i,"staffNm") ) + "[" + 
            // 						( ds_out.NameValue(i,"staffNo") == "" ? "신규입력" : ds_out.NameValue(i,"staffNo") ) + "]의  근무종료예정2차는 필수입력 항목입니다. \n";
            // 					check_Result = false;
            // 				}
            if (ds_out.getCellData(i, "ed_entDtSecond") == "" && ds_out.getCellData(i, "retireDtSecond") != "") {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무시작2차는 필수입력 항목입니다. \n";
                check_Result = false;
            }
            if (parseInt(ds_out.getCellData(i, "retireDt")) > parseInt(ds_out.getCellData(i, "entDtSecond"))) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무시작2차는 근무종료예정1차와 같거나 이전일수 없습니다. \n";
                check_Result = false;
            }
            if (parseInt(ds_out.getCellData(i, "entDtSecond")) >= parseInt(ds_out.getCellData(i, "retireDtSecond"))) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무종료예정2차는 근무시작2차와 같거나 이전일수 없습니다. \n";
                check_Result = false;
            }

            // 3차
            // 				if ( ds_out.NameValue(i,"entDtThird") != "" && ds_out.NameValue(i,"retireDtThird") == "" ) {
            // 					error_String = error_String + 
            // 						( ds_out.NameValue(i,"staffNm") == "" ? "신규입력" : ds_out.NameValue(i,"staffNm") ) + "[" + 
            // 						( ds_out.NameValue(i,"staffNo") == "" ? "신규입력" : ds_out.NameValue(i,"staffNo") ) + "]의  근무종료예정3차는 필수입력 항목입니다. \n";
            // 					check_Result = false;
            // 				}
            if (ds_out.getCellData(i, "entDtThird") == "" && ds_out.getCellData(i, "retireDtThird") != "") {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무시작3차는 필수입력 항목입니다. \n";
                check_Result = false;
            }
            if (parseInt(ds_out.getCellData(i, "retireDtSecond")) > parseInt(ds_out.getCellData(i, "entDtThird"))) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무시작3차는 근무종료예정2차와 같거나 이전일수 없습니다. \n";
                check_Result = false;
            }

            if (parseInt(ds_out.getCellData(i, "entDtThird")) >= parseInt(ds_out.getCellData(i, "retireDtThird"))) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무종료예정3차는 근무시작3차와 같거나 이전일수 없습니다. \n";
                check_Result = false;
            }

            // 4차
            // 				if ( ds_out.NameValue(i,"entDtFourth") != "" && ds_out.NameValue(i,"retireDtFourth") == "" ) {
            // 					error_String = error_String + 
            // 						( ds_out.NameValue(i,"staffNm") == "" ? "신규입력" : ds_out.NameValue(i,"staffNm") ) + "[" + 
            // 						( ds_out.NameValue(i,"staffNo") == "" ? "신규입력" : ds_out.NameValue(i,"staffNo") ) + "]의  근무종료예정4차는 필수입력 항목입니다. \n";
            // 					check_Result = false;
            // 				}
            if (ds_out.getCellData(i, "entDtFourth") == "" && ds_out.getCellData(i, "retireDtFourth") != "") {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의  근무시작4차는 필수입력 항목입니다. \n";
                check_Result = false;
            }
            if (parseInt(ds_out.getCellData(i, "retireDtThird")) > parseInt(ds_out.getCellData(i, "entDtFourth"))) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
