                        check_Result = false;
                    }

                    var VentDt4 =   ds_out.NameValue(i,"entDtFourth").toDate("YYYYMMDD");
                    VentDt4.setMonth(VentDt4.getMonth()+3);
                    var VentDt4 = VentDt4.format("YYYYMMDD");

