            */

            // 급여구분의 값에 따라 해당되는 금액이 정상적으로 입력되었는지 확인
            switch (ds_out.getCellData(i, "payGbn")) {
                case "01": // 월급제
                    if (ds_out.getCellData(i, "payAmt") == "" || ds_out.getCellData(i, "payAmt") == null) {
                        error_String = error_String +
                            (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                            (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의   월급여액은 필수항목입니다. \n";
                        check_Result = false;
                    }
                    break;

                case "02": // 일당제
                    if (ds_out.getCellData(i, "dayPayAmt") == "" || ds_out.getCellData(i, "dayPayAmt") == null) {
                        error_String = error_String +
                            (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                            (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의   일당금액은 필수항목입니다. \n";
                        check_Result = false;
                    }
                    break;

                case "03": // 시급제
                    if (ds_out.getCellData(i, "timePayAmt") == "" || ds_out.getCellData(i, "timePayAmt") == null) {
                        error_String = error_String +
                            (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                            (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의   시급금액은 필수항목입니다. \n";
                        check_Result = false;
                    }
                    break;
                default:
                    break;
            }

            // 요율에 입력된 값이 100이하인지 체크
            if (parseFloat(ds_out.getCellData(i, "extdScRt")) > 100) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의   연장할증률의 최대값은 100입니다. \n";
                check_Result = false;
            }

            if (parseFloat(ds_out.getCellData(i, "offDayScRt")) > parseInt(100)) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의   휴일할증률의 최대값은 100입니다. \n";
                check_Result = false;
            }

            if (parseFloat(ds_out.getCellData(i, "ngtDayScRt")) > parseInt(100)) {
                error_String = error_String +
                    (ds_out.getCellData(i, "staffNm") == "" ? "신규입력" : ds_out.getCellData(i, "staffNm")) + "[" +
                    (ds_out.getCellData(i, "staffNo") == "" ? "신규입력" : ds_out.getCellData(i, "staffNo")) + "]의   야간할증률의 최대값은 100입니다. \n";
                check_Result = false;
            }
        }
    }
    if (check_Result == false) {
        $c.gus.cfAlertMsg(error_String);
    }
    return check_Result;
};

