// 취소
scwin.f_Cancel = function () {

    // 취소 버튼 클릭시 그리드에서 작업한 모든 작업을 되돌린다.
    ds_out.undoAll();

    // 조회 결과 데이터가 있을시에는 신규, 수정 버튼을 활성화 하고, 조회 결과 데이터가 없을시에는 신규 버튼만 활성화 한다.
    if (ds_out.getRowCount() > 0) {
        $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify]);
        $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, pu_image]);
    } else {
        $c.gus.cfEnableBtnOnly([btn_Create]);
        $c.gus.cfDisableBtnOnly([btn_Modify, btn_Save, btn_Cancel, pu_image]);
    }

    // 저장버튼 클릭시 하단 상세 정보 출력창은 전부 비 활성화
    scwin.f_DisableData();
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

