};

scwin.f_Update = function () {
    // 수정버튼 클리시 수정/신규 버튼은 비활성화 되고, 저장, 취소 버튼은 활성화 된다. 
    $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, pu_image]);
    $c.gus.cfDisableBtnOnly([btn_Create, btn_Modify]);

    // 수정 버튼 클릭시 하단 상세 정보 출력창 전부 활성화
    scwin.f_EnableData();


    lc_payGbn.setValue(lc_payGbn.getValue());

}


//<!-- 조회 TR-->
scwin.sbm_retrieve_submiterror = function (e) {
    //cfShowError(tr_retrieve);
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);

    if (ds_out.getRowCount() > 0) {
        $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify]);
        $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, pu_image]);
    } else {
        $c.gus.cfDisableBtnOnly([btn_Modify]);
    }
};
scwin.sbm_retrieve_submitdone = function (e) {
    if (ds_out.getRowCount() > 0) {
        $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify]);
        $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, pu_image]);
        ds_out.setRowPosition(0);
        gr_out.setFocusedCell(0, 0, false);
    } else {
        $c.gus.cfDisableBtnOnly([btn_Modify]);
    }

    $c.gus.cfDisableObjects([ed_dayPayAmt, ed_timePayAmt, ed_payAmt]);

    if (ds_out.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }

    ed_totalRows.setValue(ds_out.getRowCount());
};


//<!-- 저장 TR -->
scwin.sbm_save_submitdone = function (e) {
    $c.gus.cfAlertMsg(MSG_CM_INF_001);

    // 저장버튼 클리시 수정/신규 버튼은 활성화 되고, 저장, 취소 버튼은 비활성화 된다.
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Modify]);
    $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, pu_image]);
    scwin.f_Retrieve();
};
scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};







scwin.udc_coCd_cb = function (rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_coCd.setValue(rtnList[0]);		// 코드
        ed_coNm.setValue(rtnList[5]);	// 회사명 
        ed_coCd.options.hidVal = rtnList[0];	// 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.load) {
        if ('T' == scwin.vPrivAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, img_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, img_company]);
        }

        scwin.load = false;
    }
}

