//급여구분
scwin.lc_payGbn_onchange = function (info) {
    if (lc_payGbn.getValue() == "01") { //월급
        ed_dayPayAmt.setValue(0);
        ed_timePayAmt.setValue(0);
        $c.gus.cfDisableObjects([ed_dayPayAmt, ed_timePayAmt]);
        $c.gus.cfEnableObjects([ed_payAmt]);
    } else if (lc_payGbn.getValue() == "02") { //일당제
        ed_payAmt.setValue(0);
        ed_timePayAmt.setValue(0);
        $c.gus.cfDisableObjects([ed_payAmt, ed_timePayAmt]);
        $c.gus.cfEnableObjects([ed_dayPayAmt]);
    } else {  //시급
        ed_payAmt.setValue(0);
        ed_dayPayAmt.setValue(0);
        $c.gus.cfDisableObjects([ed_payAmt, ed_dayPayAmt]);
        $c.gus.cfEnableObjects([ed_timePayAmt]);
    }
};

scwin.udc_coCd_onblurCodeEvent = function (e) {
    if (scwin.f_IsPopUp(ed_coCd, ed_coNm)) {
        scwin.f_PopUpCompanyInfo('T');
    }
};


//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function (inObj, inObj2) {
    let inValue = inObj.getValue();
    if (!inObj.options) inObj.options = {};
    let hidValue = inObj.options.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.options.hidVal = "";
        inObj2.setValue("");

        return false;
    }
    if (inValue == hidValue) return false;

    return true;
};
